using Store;

namespace Store.Tests;

[TestClass]
public sealed class ShoppingCartTests
{
    private ShoppingCart _cart = null!;

    [TestInitialize]
    public void Setup()
    {
        _cart = new ShoppingCart();
    }

    // ── AddItem ──────────────────────────────────────────────

    [TestMethod]
    public void AddItem_SingleItem_IncreasesTotal()
    {
        _cart.AddItem("SKU-001", quantity: 2, price: 9.99m);

        Assert.AreEqual(19.98m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_MultipleDistinctItems_SumsCorrectly()
    {
        _cart.AddItem("SKU-001", 1, 10.00m);
        _cart.AddItem("SKU-002", 3, 5.00m);

        Assert.AreEqual(25.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_CombinesQuantities()
    {
        _cart.AddItem("SKU-001", 1, 10.00m);
        _cart.AddItem("SKU-001", 2, 10.00m);

        Assert.AreEqual(30.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_ZeroQuantity_DoesNotAffectTotal()
    {
        _cart.AddItem("SKU-001", 0, 10.00m);

        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_NullSku_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.AddItem(null!, 1, 10.00m));
    }

    [TestMethod]
    public void AddItem_EmptySku_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.AddItem("", 1, 10.00m));
    }

    [TestMethod]
    public void AddItem_NegativeQuantity_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.AddItem("SKU-001", -1, 10.00m));
    }

    [TestMethod]
    public void AddItem_NegativePrice_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.AddItem("SKU-001", 1, -5.00m));
    }

    // ── RemoveItem ───────────────────────────────────────────

    [TestMethod]
    public void RemoveItem_ExistingItem_RemovesFromTotal()
    {
        _cart.AddItem("SKU-001", 2, 10.00m);
        _cart.AddItem("SKU-002", 1, 5.00m);

        _cart.RemoveItem("SKU-001");

        Assert.AreEqual(5.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_OnlyItem_LeavesCartEmpty()
    {
        _cart.AddItem("SKU-001", 1, 25.00m);

        _cart.RemoveItem("SKU-001");

        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_NonExistentSku_ThrowsInvalidOperationException()
    {
        Assert.ThrowsException<InvalidOperationException>(
            () => _cart.RemoveItem("NO-SUCH-SKU"));
    }

    [TestMethod]
    public void RemoveItem_NullSku_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.RemoveItem(null!));
    }

    [TestMethod]
    public void RemoveItem_ThenReaddSameSku_TotalReflectsNewItem()
    {
        _cart.AddItem("SKU-001", 1, 10.00m);
        _cart.RemoveItem("SKU-001");
        _cart.AddItem("SKU-001", 3, 7.00m);

        Assert.AreEqual(21.00m, _cart.CalculateTotal());
    }

    // ── CalculateTotal ───────────────────────────────────────

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_AfterAllItemsRemoved_ReturnsZero()
    {
        _cart.AddItem("SKU-001", 1, 10.00m);
        _cart.AddItem("SKU-002", 1, 20.00m);
        _cart.RemoveItem("SKU-001");
        _cart.RemoveItem("SKU-002");

        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_LargeQuantity_ComputesCorrectly()
    {
        _cart.AddItem("SKU-001", 1000, 0.01m);

        Assert.AreEqual(10.00m, _cart.CalculateTotal());
    }

    // ── ApplyCoupon ──────────────────────────────────────────

    [TestMethod]
    public void ApplyCoupon_ValidCode_ReducesTotal()
    {
        _cart.AddItem("SKU-001", 1, 100.00m);

        _cart.ApplyCoupon("SAVE10");

        Assert.IsTrue(_cart.CalculateTotal() < 100.00m,
            "Total should be reduced after applying a valid coupon.");
    }

    [TestMethod]
    public void ApplyCoupon_InvalidCode_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.ApplyCoupon("NOT-A-REAL-CODE"));
    }

    [TestMethod]
    public void ApplyCoupon_NullCode_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.ApplyCoupon(null!));
    }

    [TestMethod]
    public void ApplyCoupon_EmptyCode_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.ApplyCoupon(""));
    }

    [TestMethod]
    public void ApplyCoupon_SameCodeTwice_ThrowsInvalidOperationException()
    {
        _cart.AddItem("SKU-001", 1, 100.00m);
        _cart.ApplyCoupon("SAVE10");

        Assert.ThrowsException<InvalidOperationException>(
            () => _cart.ApplyCoupon("SAVE10"));
    }

    [TestMethod]
    public void ApplyCoupon_TotalNeverGoesBelowZero()
    {
        _cart.AddItem("SKU-001", 1, 1.00m);

        _cart.ApplyCoupon("SAVE10");

        Assert.IsTrue(_cart.CalculateTotal() >= 0m,
            "Total should never be negative after a coupon.");
    }

    // ── Combined workflows ───────────────────────────────────

    [TestMethod]
    public void FullWorkflow_AddRemoveCoupon_ProducesExpectedTotal()
    {
        _cart.AddItem("SKU-A", 2, 50.00m);   // 100
        _cart.AddItem("SKU-B", 1, 30.00m);   //  30
        _cart.RemoveItem("SKU-B");            // -30
        _cart.ApplyCoupon("SAVE10");          // discount

        decimal total = _cart.CalculateTotal();

        Assert.IsTrue(total > 0m && total <= 100.00m,
            $"Expected a discounted total ≤ 100, got {total}.");
    }
}

